-- User Catalog Upload v1 — personal price-list catalogs ("Мои каталоги").
--
-- A user downloads the 5-column Excel template, fills it from their own
-- price list, and uploads it. The parse-price-list edge function parses the
-- file synchronously in memory (no storage object, no server-side draft —
-- the review draft lives in the browser) and the review editor saves the
-- final rows in one atomic RPC call (create_user_catalog). Saved catalogs
-- feed the estimate constructor: the "Мои каталоги" side-panel tab and the
-- resource-name autocomplete (personal suggestions above canonical).
--
-- Ownership model: profile-personal only in v1. Org-shared and public
-- catalogs are deliberate non-goals (spec Non-Goals #1); when they arrive
-- they should follow the estimate_templates owner_kind/owner_id pattern —
-- widening this schema in a later migration mirrors how templates evolved.
--
-- matched_article_id is the optional manual link ("Артикул Rovno") from a
-- user item to a canonical library leaf (system_resource_articles). It is
-- advisory metadata: adding a matched item to an estimate line carries the
-- canonical link onto the line (system_resource_article_id), so the line
-- inherits canonical grouping/alternatives. No auto-matching in v1.
--
-- resource_type mirrors the canonical six-value set as a text CHECK (repo
-- convention — no PG enum types). price_cents is integer kopecks, matching
-- estimate lines' cost_unit_cents. unit is the display text the user chose:
-- either a canonical unit token (pcs, m², hour, ...) that the frontend
-- localizes, or free text ("своя единица"); it may be empty when the source
-- file omitted it — the editor warns but deliberately does not block
-- (user helpfulness > rigid validation).

-- 1) Catalogs -------------------------------------------------------------

create table public.user_catalogs (
  id uuid primary key default gen_random_uuid(),
  owner_profile_id uuid not null references public.profiles(id) on delete cascade,
  name text not null check (char_length(btrim(name)) between 1 and 200),
  source_filename text check (source_filename is null or char_length(source_filename) <= 255),
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

-- /home list reads are "my catalogs, newest first".
create index idx_user_catalogs_owner
  on public.user_catalogs (owner_profile_id, created_at desc);

create trigger set_user_catalogs_updated_at
before update on public.user_catalogs
for each row execute function public.set_updated_at();

-- 2) Items ----------------------------------------------------------------
--
-- Constraint notes (kept out of the table body — the backend-truth parser
-- does not strip comments inside create table):
--   user_catalog_items_price_cents_bounds — negative stays storable on
--     purpose (spec R-4: non-positive price is a keepable warning, not a
--     block); the magnitude bound mirrors the parser's MAX_PRICE_CENTS
--     (10^12 kopecks = 10 млрд ₽) so a direct RPC/API call cannot park
--     bigint-max "prices" that no UI produced.

create table public.user_catalog_items (
  id uuid primary key default gen_random_uuid(),
  catalog_id uuid not null references public.user_catalogs(id) on delete cascade,
  position integer not null default 0,
  name text not null check (char_length(btrim(name)) between 1 and 500),
  unit text not null default '' check (char_length(unit) <= 50),
  price_cents bigint not null default 0,
  resource_type text not null default 'material'
    check (resource_type in ('material', 'tool', 'labor', 'subcontractor', 'overhead', 'other')),
  supplier_sku text check (supplier_sku is null or char_length(supplier_sku) <= 100),
  matched_article_id uuid references public.system_resource_articles(id) on delete set null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  constraint user_catalog_items_price_cents_bounds
    check (price_cents between -1000000000000 and 1000000000000)
);

-- Editor reads are "items of one catalog in upload order".
create index idx_user_catalog_items_catalog
  on public.user_catalog_items (catalog_id, position);

-- Reverse-lookup support for the on delete set null FK.
create index idx_user_catalog_items_matched_article
  on public.user_catalog_items (matched_article_id);

create trigger set_user_catalog_items_updated_at
before update on public.user_catalog_items
for each row execute function public.set_updated_at();

-- 3) RLS ------------------------------------------------------------------
--
-- Owner-only on every verb. Items inherit through the parent catalog with
-- an EXISTS subquery (template_stages pattern) so ownership lives in one
-- place. No anon surface at all.

alter table public.user_catalogs enable row level security;

create policy user_catalogs_select on public.user_catalogs
  for select to authenticated
  using (owner_profile_id = auth.uid());

create policy user_catalogs_insert on public.user_catalogs
  for insert to authenticated
  with check (owner_profile_id = auth.uid());

create policy user_catalogs_update on public.user_catalogs
  for update to authenticated
  using (owner_profile_id = auth.uid())
  with check (owner_profile_id = auth.uid());

create policy user_catalogs_delete on public.user_catalogs
  for delete to authenticated
  using (owner_profile_id = auth.uid());

alter table public.user_catalog_items enable row level security;

create policy user_catalog_items_select on public.user_catalog_items
  for select to authenticated
  using (
    exists (
      select 1
      from public.user_catalogs uc
      where uc.id = user_catalog_items.catalog_id
        and uc.owner_profile_id = auth.uid()
    )
  );

create policy user_catalog_items_insert on public.user_catalog_items
  for insert to authenticated
  with check (
    exists (
      select 1
      from public.user_catalogs uc
      where uc.id = user_catalog_items.catalog_id
        and uc.owner_profile_id = auth.uid()
    )
  );

create policy user_catalog_items_update on public.user_catalog_items
  for update to authenticated
  using (
    exists (
      select 1
      from public.user_catalogs uc
      where uc.id = user_catalog_items.catalog_id
        and uc.owner_profile_id = auth.uid()
    )
  )
  with check (
    exists (
      select 1
      from public.user_catalogs uc
      where uc.id = user_catalog_items.catalog_id
        and uc.owner_profile_id = auth.uid()
    )
  );

create policy user_catalog_items_delete on public.user_catalog_items
  for delete to authenticated
  using (
    exists (
      select 1
      from public.user_catalogs uc
      where uc.id = user_catalog_items.catalog_id
        and uc.owner_profile_id = auth.uid()
    )
  );

-- 4) Grants ---------------------------------------------------------------

grant select, insert, update, delete on table public.user_catalogs to authenticated;
grant select, insert, update, delete on table public.user_catalog_items to authenticated;

-- 5) Atomic save RPC --------------------------------------------------------
--
-- The upload-review editor saves the whole reviewed catalog in one call so a
-- mid-save failure can never leave an empty catalog shell behind. SECURITY
-- INVOKER on purpose: the inserts above run under the caller's role, so the
-- RLS with-check policies stay the single authorization gate. The 1000-item
-- cap mirrors the parse-price-list truncation cap.
--
-- Item shape (jsonb array element):
--   { name, unit, price_cents, resource_type, supplier_sku,
--     matched_article_id, position }
-- Missing/empty optional fields normalize to their column defaults; position
-- falls back to the element's array index so upload order is preserved even
-- when the client omits it.

create or replace function public.create_user_catalog(
  p_name text,
  p_source_filename text,
  p_items jsonb
)
returns uuid
language plpgsql
volatile
set search_path = public
as $$
declare
  v_catalog_id uuid;
  v_count integer;
begin
  if auth.uid() is null then
    raise exception 'Not authenticated' using errcode = '42501';
  end if;

  if p_items is null or jsonb_typeof(p_items) <> 'array' then
    raise exception 'p_items must be a jsonb array';
  end if;

  v_count := jsonb_array_length(p_items);
  if v_count < 1 then
    raise exception 'Catalog must contain at least one item';
  end if;
  if v_count > 1000 then
    raise exception 'Catalog cannot exceed 1000 items';
  end if;

  insert into public.user_catalogs (owner_profile_id, name, source_filename)
  values (auth.uid(), p_name, nullif(btrim(coalesce(p_source_filename, '')), ''))
  returning id into v_catalog_id;

  insert into public.user_catalog_items
    (catalog_id, position, name, unit, price_cents, resource_type, supplier_sku, matched_article_id)
  select
    v_catalog_id,
    coalesce((item ->> 'position')::integer, ord::integer - 1),
    item ->> 'name',
    coalesce(item ->> 'unit', ''),
    coalesce((item ->> 'price_cents')::bigint, 0),
    coalesce(nullif(item ->> 'resource_type', ''), 'material'),
    nullif(btrim(coalesce(item ->> 'supplier_sku', '')), ''),
    nullif(item ->> 'matched_article_id', '')::uuid
  from jsonb_array_elements(p_items) with ordinality as t(item, ord);

  return v_catalog_id;
end;
$$;

revoke all on function public.create_user_catalog(text, text, jsonb) from public;
grant execute on function public.create_user_catalog(text, text, jsonb) to authenticated;
